import{_ as e,o as l,c as i,ae as t}from"./chunks/framework.EHGTsUvI.js";const u=JSON.parse('{"title":"主流大模型 API 接入指南：Responses、聊天接口与流式输出","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/llm-apis.md","filePath":"ai-tutorial/llm-apis.md"}'),s={name:"ai-tutorial/llm-apis.md"};function o(r,a,n,p,h,c){return l(),i("div",null,[...a[0]||(a[0]=[t(`<h1 id="主流大模型-api-接入指南-responses、聊天接口与流式输出" tabindex="-1">主流大模型 API 接入指南：Responses、聊天接口与流式输出 <a class="header-anchor" href="#主流大模型-api-接入指南-responses、聊天接口与流式输出" aria-label="Permalink to &quot;主流大模型 API 接入指南：Responses、聊天接口与流式输出&quot;">​</a></h1><blockquote><p>第一次把模型接进系统时，大家通常都会先盯着请求体怎么写，生怕少传一个字段。 可真正让人掉坑的，往往不是那几个字段本身，而是之后一整套看起来没那么“AI”、却决定系统能不能稳定上线的东西：状态怎么管、流式怎么做、结构化输出怎么接、失败怎么重试、成本怎么控。</p></blockquote><div class="warning custom-block"><p class="custom-block-title">时效性说明</p><p>本文以 <code>2026-03-17</code> 可公开查阅的官方资料为基线。不同厂商接口演进较快，具体字段与能力请以官方文档为准。</p></div><h2 id="_1-为什么很多厂商都在兼容-openai-风格" tabindex="-1">1. 为什么很多厂商都在兼容 OpenAI 风格 <a class="header-anchor" href="#_1-为什么很多厂商都在兼容-openai-风格" aria-label="Permalink to &quot;1. 为什么很多厂商都在兼容 OpenAI 风格&quot;">​</a></h2><p>今天的模型接入生态里，一个明显现象是：许多厂商会提供兼容 OpenAI 风格的接口。</p><p>原因很现实：</p><ul><li>开发者生态已经形成</li><li>大量 SDK、框架和示例围绕这一接口形态构建</li><li>应用系统更希望更换模型时少改业务代码</li></ul><p>这也是为什么理解“通用接口模式”比背某一家字段更重要。</p><h2 id="_2-当前常见的两类接口形态" tabindex="-1">2. 当前常见的两类接口形态 <a class="header-anchor" href="#_2-当前常见的两类接口形态" aria-label="Permalink to &quot;2. 当前常见的两类接口形态&quot;">​</a></h2><h3 id="_2-1-responses-风格接口" tabindex="-1">2.1 Responses 风格接口 <a class="header-anchor" href="#_2-1-responses-风格接口" aria-label="Permalink to &quot;2.1 Responses 风格接口&quot;">​</a></h3><p>以 OpenAI 当前官方文档为例，<code>/v1/responses</code> 被定位为更通用的响应接口，支持：</p><ul><li>文本输入输出</li><li>多轮状态延续</li><li>结构化输出</li><li>工具调用</li><li>内建工具扩展</li></ul><p>这类接口更适合“一个统一入口管理多种响应能力”的方向。</p><h3 id="_2-2-chat-completions-风格接口" tabindex="-1">2.2 Chat Completions 风格接口 <a class="header-anchor" href="#_2-2-chat-completions-风格接口" aria-label="Permalink to &quot;2.2 Chat Completions 风格接口&quot;">​</a></h3><p>很多模型平台和兼容层仍广泛提供 <code>chat/completions</code> 风格接口。它在生态里依然非常常见，尤其是：</p><ul><li>历史项目</li><li>框架兼容层</li><li>OpenAI-compatible 服务</li></ul><p>所以工程上经常要同时理解这两种形态。</p><h2 id="_3-接入时真正要关心什么" tabindex="-1">3. 接入时真正要关心什么 <a class="header-anchor" href="#_3-接入时真正要关心什么" aria-label="Permalink to &quot;3. 接入时真正要关心什么&quot;">​</a></h2><h3 id="_3-1-消息组织" tabindex="-1">3.1 消息组织 <a class="header-anchor" href="#_3-1-消息组织" aria-label="Permalink to &quot;3.1 消息组织&quot;">​</a></h3><p>无论是哪种接口，最关键的问题都是：</p><ul><li>system 放什么</li><li>user 放什么</li><li>历史消息保留多少</li><li>什么时候引入结构化上下文</li></ul><p>模型没有天然记忆，所以状态组织是应用自己的责任。</p><h3 id="_3-2-流式输出" tabindex="-1">3.2 流式输出 <a class="header-anchor" href="#_3-2-流式输出" aria-label="Permalink to &quot;3.2 流式输出&quot;">​</a></h3><p>对聊天、问答、长文本生成场景来说，流式输出几乎是标配。它的价值主要在于：</p><ul><li>降低用户等待焦虑</li><li>更快首字响应</li><li>让前端可以展示阶段性结果</li></ul><h3 id="_3-3-结构化输出" tabindex="-1">3.3 结构化输出 <a class="header-anchor" href="#_3-3-结构化输出" aria-label="Permalink to &quot;3.3 结构化输出&quot;">​</a></h3><p>如果输出要被程序继续消费，就应该优先考虑：</p><ul><li>JSON Schema</li><li>严格字段约束</li><li>解析失败重试</li></ul><p>这会显著提高工程稳定性。</p><h2 id="_4-接入层常见的系统设计" tabindex="-1">4. 接入层常见的系统设计 <a class="header-anchor" href="#_4-接入层常见的系统设计" aria-label="Permalink to &quot;4. 接入层常见的系统设计&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;前端 / 调用方&quot;] --&gt; B[&quot;应用服务&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;模型网关&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;外部模型 API&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; E[&quot;日志 / 指标 / 限流&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; F[&quot;重试 / 回退策略&quot;]</span></span></code></pre></div><p>建议把模型调用封装进统一网关层，而不是散落在各个业务模块里。这样更容易：</p><ul><li>控制密钥</li><li>统一重试和超时</li><li>统计成本</li><li>记录审计和日志</li></ul><h2 id="_5-常见坑" tabindex="-1">5. 常见坑 <a class="header-anchor" href="#_5-常见坑" aria-label="Permalink to &quot;5. 常见坑&quot;">​</a></h2><h3 id="_5-1-不控制历史消息长度" tabindex="-1">5.1 不控制历史消息长度 <a class="header-anchor" href="#_5-1-不控制历史消息长度" aria-label="Permalink to &quot;5.1 不控制历史消息长度&quot;">​</a></h3><p>聊天轮数一多，Token 成本和失败概率都会上升。</p><h3 id="_5-2-只要文本-不做结构化约束" tabindex="-1">5.2 只要文本，不做结构化约束 <a class="header-anchor" href="#_5-2-只要文本-不做结构化约束" aria-label="Permalink to &quot;5.2 只要文本，不做结构化约束&quot;">​</a></h3><p>这会让后续解析和自动化处理变得脆弱。</p><h3 id="_5-3-没有重试与超时策略" tabindex="-1">5.3 没有重试与超时策略 <a class="header-anchor" href="#_5-3-没有重试与超时策略" aria-label="Permalink to &quot;5.3 没有重试与超时策略&quot;">​</a></h3><p>模型调用是外部依赖，必须像其他远程服务一样治理。</p><h3 id="_5-4-不区分-回答失败-和-系统失败" tabindex="-1">5.4 不区分“回答失败”和“系统失败” <a class="header-anchor" href="#_5-4-不区分-回答失败-和-系统失败" aria-label="Permalink to &quot;5.4 不区分“回答失败”和“系统失败”&quot;">​</a></h3><p>模型返回质量问题，和网络超时、限流、服务异常是两类不同问题，应该分开处理。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>大模型 API 接入的关键，并不是学会某个请求体，而是理解一套稳定的接入模式：</p><ul><li>用统一网关管理调用</li><li>用流式输出优化体验</li><li>用结构化输出提高可消费性</li><li>用重试、限流、日志和成本统计把外部依赖纳入治理</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/api-reference/responses" target="_blank" rel="noreferrer">OpenAI Responses API Reference</a></li><li><a href="https://platform.openai.com/docs/guides/structured-outputs" target="_blank" rel="noreferrer">OpenAI: Structured outputs</a></li><li><a href="https://docs.anthropic.com/" target="_blank" rel="noreferrer">Anthropic API 文档</a></li><li>延伸阅读：<a href="./rag-intro.html">初探 RAG 架构</a></li></ul>`,47)])])}const m=e(s,[["render",o]]);export{u as __pageData,m as default};
